import React from 'react';
import { ApiError } from '../api';

interface Props { children: React.ReactNode; fallback?: React.ReactNode; }
interface State { error: Error | null; }

export class ErrorBoundary extends React.Component<Props, State> {
  state: State = { error: null };
  static getDerivedStateFromError(error: Error) { return { error }; }
  render() {
    if (this.state.error) {
      if (this.state.error instanceof ApiError) {
        return <div className="error-panel">
          <h2>Something went wrong</h2>
          <p>{this.state.error.message}</p>
          {this.state.error.status === 404 && <p>The requested resource was not found.</p>}
          <button onClick={() => this.setState({ error: null })}>Try again</button>
        </div>;
      }
      return this.props.fallback ?? <div>Unexpected error</div>;
    }
    return this.props.children;
  }
}

import { ApiError } from '../api';

const STATUS_MESSAGES: Record<number, string> = {
  400: 'Invalid request — please check your input.',
  401: 'You must be signed in to do this.',
  403: 'You don\'t have permission to do this.',
  404: 'That resource doesn\'t exist.',
  429: 'Too many requests — please slow down.',
  500: 'Server error — please try again later.',
};

interface Props {
  error: unknown;
  onRetry?: () => void;
}

export function ApiErrorMessage({ error, onRetry }: Props) {
  if (!error) return null;

  const message =
    error instanceof ApiError
      ? (STATUS_MESSAGES[error.status] ?? error.message)
      : 'An unexpected error occurred.';

  return (
    <div role="alert" className="rounded-md border border-red-300 bg-red-50 p-4 text-sm text-red-800">
      <p>{message}</p>
      {onRetry && (
        <button
          onClick={onRetry}
          className="mt-2 text-red-700 underline hover:no-underline"
        >
          Try again
        </button>
      )}
    </div>
  );
}

